"use strict";(globalThis.webpackChunkdoqumentation=globalThis.webpackChunkdoqumentation||[]).push([[3563],{73599(i,e,o){o.r(e),o.d(e,{assets:()=>l,contentTitle:()=>s,default:()=>d,frontMatter:()=>r,metadata:()=>a,toc:()=>c});const a=JSON.parse('{"id":"learning/courses/quantum-computing-in-practice/running-quantum-circuits","title":"Esecuzione di circuiti quantistici","description":"Una panoramica ad alto livello delle basi per eseguire un calcolo quantistico su scala utility.","source":"@site/i18n/it/docusaurus-plugin-content-docs/current/learning/courses/quantum-computing-in-practice/running-quantum-circuits.mdx","sourceDirName":"learning/courses/quantum-computing-in-practice","slug":"/learning/courses/quantum-computing-in-practice/running-quantum-circuits","permalink":"/learning/courses/quantum-computing-in-practice/running-quantum-circuits","draft":false,"unlisted":false,"editUrl":"https://github.com/JanLahmann/doQumentation/tree/main/docs/learning/courses/quantum-computing-in-practice/running-quantum-circuits.mdx","tags":[],"version":"current","frontMatter":{"title":"Esecuzione di circuiti quantistici","sidebar_label":"Esecuzione di circuiti quantistici","description":"Una panoramica ad alto livello delle basi per eseguire un calcolo quantistico su scala utility.","notebook_path":"learning/courses/quantum-computing-in-practice/running-quantum-circuits.ipynb"},"sidebar":"tutorialsSidebar","previous":{"title":"Introduzione","permalink":"/learning/courses/quantum-computing-in-practice/introduction"},"next":{"title":"QAOA su scala utility","permalink":"/learning/courses/quantum-computing-in-practice/utility-scale-qaoa"}}');var n=o(74848),t=o(28453);const r={title:"Esecuzione di circuiti quantistici",sidebar_label:"Esecuzione di circuiti quantistici",description:"Una panoramica ad alto livello delle basi per eseguire un calcolo quantistico su scala utility.",notebook_path:"learning/courses/quantum-computing-in-practice/running-quantum-circuits.ipynb"},s=void 0,l={},c=[{value:"Panoramica della lezione",id:"lesson-overview",level:2},{value:"Hardware \u2013 Processori quantistici IBM",id:"hardware-ibm-quantum-processors",level:2},{value:"Software: Qiskit e Qiskit Runtime",id:"software-qiskit-and-qiskit-runtime",level:2},{value:"Circuiti quantistici",id:"quantum-circuits",level:2},{value:"Progettare un circuito quantistico: i pattern Qiskit",id:"designing-a-quantum-circuit-qiskit-patterns",level:2},{value:"Map",id:"map",level:3},{value:"Optimize",id:"optimize",level:3},{value:"Qiskit Transpiler",id:"qiskit-transpiler",level:4},{value:"Soppressione degli errori",id:"error-suppression",level:4},{value:"Execute",id:"execute",level:3},{value:"Post-process",id:"post-process",level:3},{value:"Conclusione",id:"conclusion",level:2}];function u(i){const e={a:"a",code:"code",em:"em",h2:"h2",h3:"h3",h4:"h4",img:"img",li:"li",ol:"ol",p:"p",strong:"strong",ul:"ul",...(0,t.R)(),...i.components},{IBMVideo:a}=e;return a||function(i,e){throw new Error("Expected "+(e?"component":"object")+" `"+i+"` to be defined: you likely forgot to import, pass, or provide it.")}("IBMVideo",!0),(0,n.jsxs)(n.Fragment,{children:["\n",(0,n.jsxs)(e.p,{children:["Guarda il video sui circuiti quantistici e le primitive di Olivia Lanes, oppure apri il video in una finestra separata su ",(0,n.jsx)(e.a,{href:"https://youtube.com/watch?v=NTplT4WnNbk",children:"YouTube."})]}),"\n",(0,n.jsx)(a,{id:"134063416",title:"In this video, Olivia Lanes explains quantum circuits and primitives. She covers Qiskit Runtime primitives estimator and sampler."}),"\n",(0,n.jsx)(e.h2,{id:"lesson-overview",children:"Panoramica della lezione"}),"\n",(0,n.jsx)(e.p,{children:"Questa lezione offrir\xe0 una panoramica ad alto livello delle basi per eseguire un calcolo quantistico su scala utility, dall'hardware quantistico utilizzato ai principi da considerare nella progettazione di un circuito quantistico. Idealmente, alla fine di questa lezione saprai:"}),"\n",(0,n.jsxs)(e.ol,{children:["\n",(0,n.jsxs)(e.li,{children:["\n",(0,n.jsx)(e.p,{children:"Cosa sono effettivamente i computer quantistici IBM\xae. Dovrai conoscere le basi delle caratteristiche hardware per progettare in modo ottimale i tuoi circuiti quantistici ed eseguirli su di esso."}),"\n"]}),"\n",(0,n.jsxs)(e.li,{children:["\n",(0,n.jsx)(e.p,{children:"Cos'\xe8 Qiskit, cosa sono le primitive e come possiamo usarle per creare ed eseguire circuiti quantistici."}),"\n"]}),"\n",(0,n.jsxs)(e.li,{children:["\n",(0,n.jsx)(e.p,{children:"Il flusso di lavoro tipico che seguiamo per eseguire esperimenti su larga scala. Questo include la selezione delle migliori primitive per il tuo caso d'uso, la mappatura di un problema su un circuito quantistico e l'applicazione di mitigazione e soppressione degli errori, che ci permettono di sfruttare al massimo queste macchine."}),"\n"]}),"\n"]}),"\n",(0,n.jsx)(e.h2,{id:"hardware-ibm-quantum-processors",children:"Hardware \u2013 Processori quantistici IBM"}),"\n",(0,n.jsx)(e.p,{children:"Per capire come fare scelte ottimali nella progettazione di circuiti quantistici su larga scala, dobbiamo sapere qualcosa sull'hardware reale che eseguir\xe0 questi circuiti. Parliamo quindi brevemente dei qubit fisici e dei processori quantistici IBM."}),"\n",(0,n.jsxs)(e.p,{children:["I processori quantistici IBM sono costruiti usando qubit transmon superconduttori, che sono circuiti elettrici composti da una ",(0,n.jsx)(e.em,{children:"giunzione Josephson"})," e un condensatore collegati in parallelo. La giunzione Josephson \xe8 un induttore non lineare creato da due strati sovrapposti di metallo superconduttore con una barriera isolante tra di essi. A temperature molto basse, gli elettroni nei superconduttori si accoppiano per formare quello che \xe8 noto come coppia di Cooper. Le coppie di Cooper possono spontaneamente attraversare per effetto tunnel la barriera isolante da un lato all'altro della giunzione. Questo comportamento di tunneling d\xe0 origine alle propriet\xe0 non lineari che creano il nostro qubit."]}),"\n",(0,n.jsxs)(e.p,{children:["Linee di trasmissione a microonde sono fabbricate sul chip per inviare segnali a microonde ai qubit. Quando applichiamo impulsi a microonde altamente calibrati \u2014 con frequenza, ampiezza, forma e durata specifiche \u2014 alle linee, possiamo far eseguire ai qubit operazioni specifiche. Questo costituisce la base dei nostri gate quantistici. Fabrichiamo il chip in modo che i qubit vicini siano collegati in una struttura reticolare specifica chiamata reticolo heavy-hex. Questa connettivit\xe0 \u2014 la cosiddetta ",(0,n.jsx)(e.em,{children:"topologia"})," \u2014 dei nostri processori \xe8 un fattore importante da considerare nella progettazione di un circuito, come discuteremo pi\xf9 avanti nella lezione."]}),"\n",(0,n.jsx)(e.p,{children:"Le istruzioni per l'impulso a microonde partono dal tuo computer, passano attraverso il cloud e arrivano all'elettronica di controllo a temperatura ambiente, che interpreta quelle istruzioni e genera fisicamente gli impulsi. Dopo che le unit\xe0 di controllo a temperatura ambiente creano gli impulsi, questi viaggiano attraverso cavi verso un refrigeratore a diluizione e infine al chip quantistico. Il segnale entra nei risonatori, attraversa un wirebond e poi scorre lungo la linea di trasmissione fino ai nostri qubit."}),"\n",(0,n.jsxs)(e.p,{children:["IBM dispone di decine di computer quantistici in tutto il mondo, e di recente abbiamo aggiornato la nostra flotta per avere esclusivamente processori con pi\xf9 di 100 qubit. Alcuni si trovano in un data center quantistico IBM nello stato di New York e sono resi disponibili tramite cloud per l'uso di tutti \u2014 e alcuni sono sistemi dedicati, on-premises, che supportano i partner nella IBM Quantum\xae Network. Puoi accedere a ",(0,n.jsx)(e.a,{href:"https://quantum.cloud.ibm.com",children:"quantum.cloud.ibm.com"})," per vedere quali processori hai a disposizione."]}),"\n",(0,n.jsx)(e.p,{children:"Ogni processore elenca tre metriche di prestazione, di cui abbiamo parlato nella lezione precedente, ma come promemoria, sono: numero di qubit, EPLG e CLOPS."}),"\n",(0,n.jsxs)(e.ul,{children:["\n",(0,n.jsxs)(e.li,{children:["\n",(0,n.jsxs)(e.p,{children:[(0,n.jsx)(e.strong,{children:"Numero di qubit."})," Questo \xe8 autoesplicativo: \xe8 il numero totale di qubit disponibili su un singolo processore quantistico. Per un problema relativamente grande su scala utility, dovrai assicurarti di usare un processore con abbastanza qubit per affrontare il problema. Ma il solo numero di qubit non \xe8 l'unica cosa che conta."]}),"\n"]}),"\n",(0,n.jsxs)(e.li,{children:["\n",(0,n.jsxs)(e.p,{children:[(0,n.jsx)(e.strong,{children:"EPLG,"}),' ovvero "errors per layered gate" (errori per gate a strati). \xc8 una misura della qualit\xe0 dei qubit e dei gate quantistici. Misura l\'errore medio che ogni gate introduce in un circuito che intrecca qubit vicini in una catena di 100 qubit. Vuoi che questo valore sia il pi\xf9 piccolo possibile.']}),"\n"]}),"\n",(0,n.jsxs)(e.li,{children:["\n",(0,n.jsxs)(e.p,{children:[(0,n.jsx)(e.strong,{children:"CLOPS,"}),' ovvero "circuit layer operations per second" (operazioni su strati di circuito al secondo). Quantifica la velocit\xe0 del processore. Misura quanti strati di un certo circuito di benchmark chiamato circuito quantum volume una unit\xe0 di elaborazione quantistica (QPU) pu\xf2 eseguire per unit\xe0 di tempo. Pi\xf9 alto \xe8 il numero, pi\xf9 velocemente possiamo calcolare.']}),"\n"]}),"\n"]}),"\n",(0,n.jsx)(e.p,{children:"L'importanza di ciascuna di queste metriche varia a seconda dell'applicazione specifica, e nelle lezioni future esamineremo esempi reali per vedere come ciascuno di questi fattori pu\xf2 influenzare il risultato di un calcolo."}),"\n",(0,n.jsx)(e.h2,{id:"software-qiskit-and-qiskit-runtime",children:"Software: Qiskit e Qiskit Runtime"}),"\n",(0,n.jsx)(e.p,{children:"Per trasformare il tuo problema quantistico in istruzioni per un computer quantistico, userai Qiskit, il kit di sviluppo software open-source progettato per il lavoro sui computer quantistici sviluppato da IBM. C'\xe8 anche l'Ecosistema Qiskit \u2014 una raccolta di tutorial software e funzioni che si basano o estendono le funzionalit\xe0 principali di Qiskit \u2014 e Qiskit Runtime \u2014 un servizio di calcolo quantistico e modello di programmazione che consente agli utenti di progettare e ottimizzare i propri carichi di lavoro quantistici e di eseguirli in modo efficiente usando le Primitive di Qiskit Runtime."}),"\n",(0,n.jsx)(e.p,{children:"Una primitiva \xe8 un piccolo blocco costruttivo che puoi usare per progettare un circuito o un job pi\xf9 grande. Le due primitive pi\xf9 importanti per noi sono il Sampler e l'Estimator, di cui parleremo pi\xf9 approfonditamente a breve."}),"\n",(0,n.jsxs)(e.p,{children:["Con la recente uscita di Qiskit v1.0, Qiskit \xe8 diventato pi\xf9 performante e stabile che mai. Quindi, per chi sta iniziando adesso, \xe8 il momento perfetto! Per chi conosce gi\xe0 Qiskit, sar\xe0 necessario scaricare e reinstallare la versione pi\xf9 recente. Per una guida completa all'installazione, visita la guida ",(0,n.jsx)(e.a,{href:"/guides/install-qiskit",children:"Install Qiskit"}),"."]}),"\n",(0,n.jsx)(e.h2,{id:"quantum-circuits",children:"Circuiti quantistici"}),"\n",(0,n.jsxs)(e.p,{children:["Ora siamo pronti a discutere il fondamento dei programmi quantistici: i circuiti quantistici. Questa sezione servir\xe0 solo come ripasso \u2014 se non hai familiarit\xe0 con i circuiti quantistici, ti consigliamo di approfondire l'argomento visitando la lezione ",(0,n.jsx)(e.a,{href:"/learning/courses/basics-of-quantum-information/quantum-circuits/introduction",children:"Circuiti Quantistici"}),' nel corso "Nozioni di base sull\'informazione quantistica" prima di continuare.']}),"\n",(0,n.jsx)(e.p,{children:"Un circuito quantistico \xe8 una rete di gate quantistici e misurazioni collegate da fili che rappresentano i qubit, come mostrato di seguito. I circuiti quantistici possono essere letti come uno spartito musicale, da sinistra a destra, partendo dal tempo 0 a sinistra. I qubit virtuali \u2014 quelli che non sono ancora stati assegnati a un qubit fisico su un processore \u2014 sono elencati in ordine crescente dall'alto verso il basso."}),"\n",(0,n.jsx)(e.p,{children:'I gate sono rappresentati da simboli diversi sui fili dei qubit coinvolti. I gate a qubit singolo \u2014 come un gate Hadamard, raffigurato di seguito (il rettangolo con la H) \u2014 influenzano solo il qubit sul cui filo sono posizionati. I gate a pi\xf9 qubit \u2014 come un gate CNOT, anch\'esso mostrato di seguito (il segno pi\xf9 nel cerchio con una linea connessa a q0) \u2014 influenzano due o pi\xf9 qubit. Nel gate CNOT raffigurato, lo stato di q1 cambia in base allo stato di q0. Dopo che tutti i gate sono stati eseguiti, possiamo misurare i qubit, indicati dai gate neri con il simbolo di misurazione. I risultati delle misurazioni vengono scritti sui registri classici, il bus "meas" a doppia linea in basso.'}),"\n",(0,n.jsx)(e.p,{children:(0,n.jsx)(e.img,{alt:"Esempio di circuito quantistico semplice",src:o(54776).A+"",width:"2715",height:"1424"})}),"\n",(0,n.jsx)(e.p,{children:'Una caratteristica importante di un circuito \xe8 la sua profondit\xe0. La profondit\xe0 di un circuito quantistico \xe8 il numero minimo di "strati" di gate quantistici, eseguiti in parallelo, necessari per completare il circuito. I gate quantistici possono essere eseguiti in parallelo (allo stesso tempo) ogni volta che non hanno qubit in comune. Ma se due o pi\xf9 gate agiscono sullo stesso qubit, non possiamo eseguirli in parallelo \u2014 devono essere eseguiti in due strati separati, uno dopo l\'altro.'}),"\n",(0,n.jsx)(e.p,{children:"C'\xe8 un altro modo, meno ovvio, per determinare la profondit\xe0 di un circuito, giocando a una sorta di gioco. Le regole sono semplici: partendo da qualsiasi filo di qubit a sinistra, devi spostarti verso destra e contare il numero di gate che incontri lungo il percorso. Puoi saltare su un filo vicino solo quando \xe8 connesso al tuo filo corrente da un gate a pi\xf9 qubit. L'obiettivo \xe8 massimizzare il numero di gate che incontri lungo il percorso. Questo numero massimale corrisponde anche alla profondit\xe0 del circuito."}),"\n",(0,n.jsx)(e.p,{children:(0,n.jsx)(e.img,{alt:"Esempio di circuito a nove strati",src:o(77815).A+"",width:"3840",height:"1893"})}),"\n",(0,n.jsx)(e.p,{children:"Poich\xe9 i gate quantistici richiedono tempo per essere implementati, la profondit\xe0 di un circuito corrisponde approssimativamente alla quantit\xe0 di tempo necessaria a un computer quantistico per eseguire il circuito. Alcune macchine sono pi\xf9 adatte a circuiti con grande profondit\xe0 rispetto ad altre, a causa dei tempi di decoerenza dei qubit sul processore. Quindi, dobbiamo conoscere la profondit\xe0 di un circuito per sapere se pu\xf2 essere eseguito su un determinato dispositivo."}),"\n",(0,n.jsx)(e.h2,{id:"designing-a-quantum-circuit-qiskit-patterns",children:"Progettare un circuito quantistico: i pattern Qiskit"}),"\n",(0,n.jsx)(e.p,{children:"Come si fa a progettare ed eseguire un circuito quantistico? Il modo pi\xf9 semplice per capire un tipico flusso di lavoro nel calcolo quantistico \xe8 attraverso i pattern Qiskit. I pattern Qiskit sono un framework concettuale che consente agli utenti di eseguire carichi di lavoro quantistici implementando determinati passaggi con strumenti modulari. Questo consente alle attivit\xe0 di calcolo quantistico di essere eseguite da una potente infrastruttura di calcolo eterogenea (CPU/GPU/QPU). I passaggi possono essere eseguiti come servizio e possono incorporare la gestione delle risorse, consentendo la composizione senza soluzione di continuit\xe0 di nuove funzionalit\xe0 man mano che vengono sviluppate."}),"\n",(0,n.jsx)(e.p,{children:"Ecco i passaggi principali, che gli utenti Qiskit esperti riconosceranno facilmente."}),"\n",(0,n.jsxs)(e.ol,{children:["\n",(0,n.jsxs)(e.li,{children:["\n",(0,n.jsxs)(e.p,{children:[(0,n.jsx)(e.strong,{children:"Map (Mappatura)."})," Questo passaggio formalizza come prendiamo un problema generale che ci interessa e come capire come mapparlo su un computer quantistico sotto forma di circuito quantistico."]}),"\n"]}),"\n",(0,n.jsxs)(e.li,{children:["\n",(0,n.jsxs)(e.p,{children:[(0,n.jsx)(e.strong,{children:"Optimize (Ottimizzazione)."})," In questo passaggio usiamo il Transpiler di Qiskit per instradare e disporre il circuito sull'hardware fisico di qubit reale. Questo include la traduzione dei singoli gate quantistici in sequenze di operazioni che vengono eseguite sull'hardware, nonch\xe9 un'ottimizzazione della disposizione dei gate."]}),"\n"]}),"\n",(0,n.jsxs)(e.li,{children:["\n",(0,n.jsxs)(e.p,{children:[(0,n.jsx)(e.strong,{children:"Execute (Esecuzione)."})," Le primitive di Qiskit Runtime forniscono l'interfaccia con l'hardware IBM Quantum che consente ai circuiti transpilati di essere eseguiti. Questo passaggio include anche l'uso di tecniche di soppressione e mitigazione degli errori, che possono essere in gran parte astratte dall'utente."]}),"\n"]}),"\n",(0,n.jsxs)(e.li,{children:["\n",(0,n.jsxs)(e.p,{children:[(0,n.jsx)(e.strong,{children:"Post-process (Post-elaborazione)."})," In questo passaggio i dati provenienti dal processore quantistico vengono elaborati, fornendo all'utente risultati utili sul problema originale. Fondamentalmente, questo comprende qualsiasi ulteriore analisi dei dati acquisiti."]}),"\n"]}),"\n"]}),"\n",(0,n.jsx)(e.h3,{id:"map",children:"Map"}),"\n",(0,n.jsx)(e.p,{children:"Il passaggio Map pone essenzialmente la domanda: \"Come traduco il mio problema in un circuito quantistico che possa essere eseguito ragionevolmente sull'hardware quantistico?\" Non c'\xe8 dubbio: la mappatura \xe8 un problema difficile e un'area di ricerca attiva. Non esiste un metodo infallibile che garantisca il successo, ma ci sono linee guida consigliate ed esempi di problemi che sappiamo gi\xe0 come mappare."}),"\n",(0,n.jsx)(e.p,{children:"La prima linea guida \xe8 lasciare che i computer classici facciano tutto il lavoro in cui sono migliori. I compiti facili per i computer classici probabilmente non beneficeranno di un computer quantistico. I computer quantistici sono per problemi che sono classicamente difficili. Naturalmente, se questa \xe8 la prima volta che usi Qiskit o un computer quantistico, non preoccuparti di trovare un problema computazionalmente complesso. Scomponilo in problemi pi\xf9 piccoli e maneggevoli che puoi imparare ad affrontare prima di puntare direttamente a un progetto su scala utility."}),"\n",(0,n.jsx)(e.p,{children:"Successivamente, traduci i risultati del tuo problema che vuoi misurare o comprendere in un valore di aspettazione o in una funzione di costo. Una funzione di costo \xe8 una funzione specifica del problema che definisce l'obiettivo del problema come qualcosa da minimizzare o massimizzare. Pu\xf2 essere usata per vedere quanto bene uno stato di prova o una soluzione si comporta rispetto a quell'obiettivo. Questa nozione pu\xf2 essere applicata a varie applicazioni in chimica, machine learning, finanza, ottimizzazione e cos\xec via \u2014 non importa necessariamente da quale disciplina ti stai approcciando al problema."}),"\n",(0,n.jsx)(e.p,{children:"Tieni anche presente che l'hardware che utilizzerai ha una topologia specifica, come abbiamo discusso nella sezione hardware. Alcuni qubit sono connessi e altri no \u2014 dovrai mappare il tuo problema su un circuito che rispetti la topologia heavy-hex dei processori quantistici IBM."}),"\n",(0,n.jsx)(e.p,{children:"Per ora, la cosa pi\xf9 importante da tenere a mente \xe8 che questa fase richiede pratica. Devi avere una buona comprensione non solo del tuo problema, ma anche delle capacit\xe0 dell'hardware \u2014 e nelle lezioni future esamineremo esempi e casi d'uso specifici per vedere come bilanciare tutte queste considerazioni."}),"\n",(0,n.jsx)(e.h3,{id:"optimize",children:"Optimize"}),"\n",(0,n.jsx)(e.p,{children:"Successivamente, dovremo scegliere un processore quantistico che abbia abbastanza qubit di qualit\xe0 sufficientemente alta da poter eseguire il nostro circuito quantistico. Prendi queste decisioni guidato dalle tre metriche di cui abbiamo discusso nella sezione hardware: numero di qubit, EPLG e CLOPS."}),"\n",(0,n.jsx)(e.p,{children:"Poi ottimizziamo il nostro circuito per l'hardware selezionato. Per prima cosa, dobbiamo disporre e instradare il nostro circuito in modo efficiente. Layout si riferisce alla mappatura dei qubit virtuali nel circuito sui qubit fisici del processore. Routing si riferisce alla modifica del circuito in modo che la connettivit\xe0 tra i qubit virtuali nel circuito corrisponda alla connettivit\xe0 dei qubit fisici sul processore. Ci sono un paio di cose da tenere a mente durante la fase di layout e routing."}),"\n",(0,n.jsxs)(e.ol,{children:["\n",(0,n.jsxs)(e.li,{children:["\n",(0,n.jsx)(e.p,{children:"Non tutti i qubit sono connessi. Alcuni sono molto lontani l'uno dall'altro sul chip, e dobbiamo ridurre o eliminare le interazioni a lunga distanza dove possibile. Potresti applicare una sequenza di gate SWAP tra qubit vicini per spostare le informazioni dei qubit, ma i gate SWAP sono costosi e soggetti a errori, quindi potrebbero esserci modi migliori per farlo. Cerca di evitare troppi gate SWAP costosi."}),"\n"]}),"\n",(0,n.jsxs)(e.li,{children:["\n",(0,n.jsxs)(e.p,{children:["Layout e routing sono processi iterativi. Puoi farlo a mano, ma esiste anche uno strumento Qiskit chiamato ",(0,n.jsx)(e.code,{children:"mapomatic"}),", che pu\xf2 fare raccomandazioni per un layout di qubit fisici basato su tassi di errore approssimativi. Il Transpiler (di cui parleremo a breve) pu\xf2 anche fare un suggerimento informato."]}),"\n"]}),"\n"]}),"\n",(0,n.jsx)(e.p,{children:"Successivamente, possiamo comporre sequenze di gate a qubit singolo che agiscono sullo stesso qubit in gate singoli \u2014 e a volte possiamo anche eliminare gate o combinazioni di gate non necessari. Ad esempio, alcune combinazioni di gate possono essere ridotte a combinazioni pi\xf9 semplici \u2014 e in effetti, a volte una combinazione di gate pu\xf2 equivalere all'operazione identit\xe0, quindi possiamo semplicemente eliminarli. Puoi farlo automaticamente usando il Transpiler di Qiskit \u2014 ma puoi anche farlo manualmente gate per gate se vuoi avere pi\xf9 controllo."}),"\n",(0,n.jsx)(e.p,{children:"Una volta migliorati il layout del circuito, il routing e il numero di gate \u2014 sia a mano che usando il Transpiler \u2014 di solito vogliamo visualizzare il nostro circuito per assicurarci che la temporizzazione di tutti i gate abbia senso. C'\xe8 un argomento che puoi impostare nel Transpiler per visualizzare la timeline del tuo circuito e assicurarti che tutto sia allineato come ti aspetteresti."}),"\n",(0,n.jsx)(e.h4,{id:"qiskit-transpiler",children:"Qiskit Transpiler"}),"\n",(0,n.jsx)(e.p,{children:"Come menzionato in precedenza, il Qiskit Transpiler pu\xf2 essere usato per aiutare nelle prime fasi del flusso di lavoro dei pattern. Approfondiamo ora le sue capacit\xe0 in modo pi\xf9 dettagliato. Pu\xf2 riscrivere un circuito in input in modo che corrisponda alla topologia di un dispositivo quantistico specifico e ottimizzare il circuito per l'esecuzione e la resilienza al rumore. Riscrive anche un dato circuito nei gate base del processore quantistico specifico che hai selezionato da usare."}),"\n",(0,n.jsx)(e.p,{children:"Qiskit ha quattro pipeline di transpilazione integrate corrispondenti a diversi livelli di ottimizzazione, e a meno che tu non abbia gi\xe0 familiarit\xe0 con l'ottimizzazione dei circuiti quantistici, ti consigliamo di usarne una. Per impostazione predefinita, il processo di transpilazione include questi sei passaggi:"}),"\n",(0,n.jsxs)(e.ol,{children:["\n",(0,n.jsxs)(e.li,{children:["\n",(0,n.jsx)(e.p,{children:"Inizializzazione. Questa fase esegue tutti i passaggi iniziali richiesti prima di iniziare a incorporare il circuito nel backend. Di solito comporta lo srotolamento di istruzioni personalizzate e la conversione del circuito in soli gate a uno e due qubit."}),"\n"]}),"\n",(0,n.jsxs)(e.li,{children:["\n",(0,n.jsxs)(e.p,{children:["Layout. Questa fase mappa i qubit virtuali nel circuito sui qubit fisici di un backend. Vedi ",(0,n.jsx)(e.a,{href:"https://docs.quantum.ibm.com/api/qiskit/transpiler#layout-stage",children:"Layout Stage"})," per maggiori dettagli."]}),"\n"]}),"\n",(0,n.jsxs)(e.li,{children:["\n",(0,n.jsxs)(e.p,{children:["Routing. Questa fase viene eseguita dopo che \xe8 stato applicato un layout e inietta gate (come gate SWAP) nel circuito originale per renderlo compatibile con la connettivit\xe0 del backend. Vedi ",(0,n.jsx)(e.a,{href:"https://docs.quantum.ibm.com/api/qiskit/transpiler#routing-stage",children:"Routing Stage"})," per maggiori dettagli."]}),"\n"]}),"\n",(0,n.jsxs)(e.li,{children:["\n",(0,n.jsxs)(e.p,{children:["Traduzione. Questa fase traduce i gate nel circuito nell'insieme base del backend target. Vedi ",(0,n.jsx)(e.a,{href:"https://docs.quantum.ibm.com/api/qiskit/transpiler#translation-stage",children:"Translation Stage"})," per maggiori dettagli."]}),"\n"]}),"\n",(0,n.jsxs)(e.li,{children:["\n",(0,n.jsx)(e.p,{children:"Ottimizzazione. Questa fase esegue ripetutamente il ciclo di ottimizzazione principale fino a quando non viene raggiunta una condizione (come il raggiungimento di una certa profondit\xe0 target). Abbiamo quattro livelli di ottimizzazione diversi tra cui scegliere, descritti di seguito."}),"\n"]}),"\n",(0,n.jsxs)(e.li,{children:["\n",(0,n.jsx)(e.p,{children:"Scheduling. Questa fase \xe8 per tutti i passaggi di scheduling consapevoli dell'hardware. Ad alto livello, lo scheduling pu\xf2 essere pensato come l'inserimento di ritardi nel circuito per tenere conto del tempo di inattivit\xe0 dei qubit tra l'esecuzione delle istruzioni."}),"\n"]}),"\n"]}),"\n",(0,n.jsxs)(e.p,{children:["Ci sono quattro livelli di ottimizzazione che vanno da 0 a 3, dove livelli di ottimizzazione pi\xf9 alti richiedono pi\xf9 tempo e sforzo computazionale ma possono produrre un circuito migliore. Il livello di ottimizzazione 0 \xe8 pensato per esperimenti di caratterizzazione del dispositivo e, come tale, mappa solo il circuito in input ai vincoli del backend target, senza eseguire alcuna ottimizzazione. Il livello di ottimizzazione 3 dedica il massimo sforzo per ottimizzare il circuito. Tuttavia, poich\xe9 molte delle tecniche di ottimizzazione nel Transpiler sono basate su euristiche, dedicare pi\xf9 sforzo computazionale non sempre si traduce in un miglioramento della qualit\xe0 del circuito in output. Se vuoi approfondire ulteriormente, consulta la ",(0,n.jsx)(e.a,{href:"https://docs.quantum.ibm.com/api/qiskit/transpiler",children:"documentazione del Transpiler"})," nella documentazione di Qiskit."]}),"\n",(0,n.jsx)(e.h4,{id:"error-suppression",children:"Soppressione degli errori"}),"\n",(0,n.jsx)(e.p,{children:"Il primo passo per ridurre gli errori in un circuito \xe8 ottimizzare il layout, il routing e minimizzare il numero di gate, cosa che abbiamo gi\xe0 fatto, usando il Transpiler o da soli. Parliamo ora di alcuni metodi pi\xf9 sofisticati di soppressione degli errori."}),"\n",(0,n.jsx)(e.p,{children:'La soppressione degli errori si riferisce a una classe di tecniche che trasformano un circuito durante la compilazione per minimizzare gli errori. \xc8 distinta dalla mitigazione degli errori, di cui parleremo pi\xf9 avanti nella sezione "Execute" qui sotto. Le due forme pi\xf9 comuni di soppressione degli errori che usiamo sono il dynamical decoupling e il Pauli twirling:'}),"\n",(0,n.jsxs)(e.ol,{children:["\n",(0,n.jsx)(e.li,{children:"Il dynamical decoupling viene usato per annullare efficacemente parte del rumore ambientale introdotto quando un qubit rimane inattivo. Applicando una serie di gate in momenti specifici, puoi far s\xec che il rumore che si accumula in una parte del periodo di inattivit\xe0 annulli approssimativamente il rumore nell'altra parte."}),"\n",(0,n.jsx)(e.li,{children:"Il Pauli twirling \xe8 un modo per inserire gate casuali non per annullare il rumore, come nel dynamical decoupling, ma per semplificarlo. Inserendo gate casuali, si impedisce agli effetti di errori diversi di accumularsi cos\xec rapidamente, e si rende il rumore pi\xf9 facile da caratterizzare, poich\xe9 ora ha una natura stocastica. Questo metodo costituisce anche la base di una potente tecnica di mitigazione degli errori, di cui parleremo di seguito."}),"\n"]}),"\n",(0,n.jsx)(e.h3,{id:"execute",children:"Execute"}),"\n",(0,n.jsx)(e.p,{children:"Ora siamo pronti per eseguire il programma quantistico. Le primitive di Qiskit Runtime forniscono un'interfaccia con l'hardware IBM Quantum, e astraggono anche la soppressione e la mitigazione degli errori dall'utente. Ci sono due primitive tra cui scegliere: il Sampler e l'Estimator."}),"\n",(0,n.jsxs)(e.p,{children:["Il ",(0,n.jsx)(e.a,{href:"https://docs.quantum.ibm.com/api/qiskit-ibm-runtime/sampler",children:"Sampler di Qiskit Runtime"})," esegue il circuito pi\xf9 volte su un dispositivo quantistico, effettuando misurazioni a ogni esecuzione, e ricostruisce la distribuzione di probabilit\xe0 dalle stringhe di bit recuperate. Pi\xf9 esecuzioni (o shot) vengono effettuate, pi\xf9 accurati saranno i risultati, ma questo richiede pi\xf9 tempo e risorse quantistiche. Nello specifico, calcola la probabilit\xe0 di ottenere ogni possibile stato della base standard misurando lo stato preparato dal circuito."]}),"\n",(0,n.jsxs)(e.p,{children:["L'",(0,n.jsx)(e.a,{href:"https://docs.quantum.ibm.com/api/qiskit-ibm-runtime/estimator",children:"Estimator di Qiskit Runtime"})," usa un processo algebrico complesso per stimare il valore di aspettazione su un dispositivo quantistico reale, scomponendo l'osservabile in una combinazione di altri osservabili con autobasi note."]}),"\n",(0,n.jsxs)(e.p,{children:["Il passaggio Execute \xe8 anche quando possiamo selezionare la strategia di ",(0,n.jsx)(e.em,{children:"mitigazione degli errori"}),". La ",(0,n.jsx)(e.em,{children:"mitigazione degli errori"})," si riferisce a tecniche che consentono agli utenti di ridurre gli errori del circuito modellando il rumore del dispositivo presente al momento dell'esecuzione. In genere, ci\xf2 comporta un overhead di pre-elaborazione quantistica relativo all'addestramento del modello e un overhead di post-elaborazione classica per mitigare gli errori nei risultati grezzi usando il modello generato. In cambio di questo overhead, siamo in grado di ottenere risultati molto pi\xf9 accurati."]}),"\n",(0,n.jsx)(e.p,{children:"Ci sono molteplici tecniche che possiamo implementare per la mitigazione degli errori. Ne discuteremo tre, in ordine crescente di resilienza agli errori, ma anche, di conseguenza, in ordine crescente di costo computazionale. Tieni presente, tuttavia, che questa \xe8 un'area di ricerca attiva \u2014 quindi continueremo probabilmente a inventarne di nuove e a migliorare quelle vecchie."}),"\n",(0,n.jsx)(e.p,{children:"Al livello di resilienza 0, il Transpiler non fa nulla al tuo circuito."}),"\n",(0,n.jsx)(e.p,{children:"Al livello 1, introduce un metodo chiamato Twirled Readout Error eXtinction (T-REX). T-REX usa il Pauli twirling, come discusso nella sezione sulla soppressione degli errori. Come accennato, inserire gate casuali nel circuito pu\xf2 far sembrare stocastico anche un rumore molto complicato e difficile da modellare, e molto pi\xf9 facile da tenere in conto o sottrarre in post-elaborazione."}),"\n",(0,n.jsx)(e.p,{children:"Al livello di resilienza 2, viene aggiunta la Zero Noise Extrapolation (ZNE). Questa \xe8 una tecnica popolare con cui abbiamo avuto molto successo di recente. L'idea alla base di ZNE potrebbe essere un po' sorprendente \u2014 in realt\xe0 aggiungiamo rumore sopra quello gi\xe0 presente! Ma questo ci consente di estrapolare nella direzione inversa, per prevedere come sarebbero i risultati se ci fosse sempre meno rumore."}),"\n",(0,n.jsx)(e.p,{children:"L'aggiunta di rumore pu\xf2 essere realizzata in diversi modi. Ad esempio, possiamo allungare i gate per renderli pi\xf9 lunghi e quindi pi\xf9 soggetti a errori, oppure eseguire pi\xf9 gate che alla fine risultano nell'operazione identit\xe0, cos\xec il circuito non cambia funzionalmente ma campioniamo deliberatamente pi\xf9 rumore. Devi farlo per\xf2 per ogni circuito e per ogni valore di aspettazione che vuoi tenere traccia \u2014 quindi puoi capire come possa risultare computazionalmente costoso."}),"\n",(0,n.jsx)(e.p,{children:"Un tipo specifico di ZNE \xe8 chiamato Probabilistic Error Amplification (PEA). Una volta appreso un modello di rumore per un gate, PEA funziona campionando gli errori da quel modello di rumore e instandoli deliberatamente nel circuito. Questo non \xe8 ancora disponibile in Qiskit, ma lo sar\xe0 pi\xf9 avanti quest'anno."}),"\n",(0,n.jsx)(e.p,{children:"L'ultima forma di mitigazione degli errori di cui parleremo \xe8 la Probabilistic Error Cancellation (PEC). Invece di essere al 3\xb0 livello di resilienza, PEC \xe8 una capacit\xe0 speciale che devi attivare manualmente in Qiskit, perch\xe9 le risorse computazionali richieste non scalano bene rispetto alle altre tecniche di mitigazione degli errori. Inizi imparando a conoscere il rumore che influenza il tuo circuito \u2014 esegui circuiti di apprendimento del rumore o di caratterizzazione del rumore per ogni strato unico di gate a due qubit nel tuo circuito. Questi risultati ti consentono di descrivere il rumore in termini di operatori di Pauli. Una volta noti questi termini di rumore, puoi modificare i tuoi circuiti in modo che abbiano effettivamente i gate di Pauli opposti integrati per annullare questi canali di rumore. In un certo senso, il processo \xe8 simile al modo in cui funzionano le cuffie con cancellazione del rumore. Tuttavia, questo modo di annullare il rumore \xe8 molto costoso, con un tempo di esecuzione che cresce rapidamente in modo esponenziale in funzione del numero di gate, quindi potrebbe non essere la scelta migliore per un circuito molto grande."}),"\n",(0,n.jsx)(e.h3,{id:"post-process",children:"Post-process"}),"\n",(0,n.jsx)(e.p,{children:"La fase di post-elaborazione \xe8 dove visualizziamo e analizziamo l'output del nostro circuito quantistico. Ci sono diversi strumenti Qiskit disponibili per farlo, come i moduli di visualizzazione e quantum-info. Non li tratteremo qui, ma vedremo questi moduli in azione mentre ci immergiamo in alcuni esempi di applicazioni nelle lezioni future."}),"\n",(0,n.jsx)(e.h2,{id:"conclusion",children:"Conclusione"}),"\n",(0,n.jsx)(e.p,{children:"Speriamo che questa lezione ti abbia offerto un tour rapido delle principali considerazioni e del flusso di lavoro che utilizziamo quando vogliamo eseguire un calcolo quantistico su scala utility. Era ricca di informazioni, e molte di esse non assimilerai finch\xe9 non vedi alcuni esempi concreti in cui questi concetti teorici vengono messi in pratica. Quindi, questo \xe8 ci\xf2 che costituir\xe0 il resto del corso. Dopotutto, questo corso non si chiama Quantum Computing in Practice per niente!"}),"\n",(0,n.jsx)(e.p,{children:"La prossima volta, esamineremo un esempio specifico di come usare il flusso di lavoro dei pattern Qiskit per progettare ed eseguire un circuito quantistico che risolve il classico problema della teoria dei grafi chiamato MaxCut."})]})}function d(i={}){const{wrapper:e}={...(0,t.R)(),...i.components};return e?(0,n.jsx)(e,{...i,children:(0,n.jsx)(u,{...i})}):u(i)}},77815(i,e,o){o.d(e,{A:()=>a});const a=o.p+"assets/images/circuitdepth-e2f15da4f6d03fbe250110f56450f666.avif"},54776(i,e,o){o.d(e,{A:()=>a});const a="data:image/avif;base64,"},28453(i,e,o){o.d(e,{R:()=>r,x:()=>s});var a=o(96540);const n={},t=a.createContext(n);function r(i){const e=a.useContext(t);return a.useMemo(function(){return"function"==typeof i?i(e):{...e,...i}},[e,i])}function s(i){let e;return e=i.disableParentContext?"function"==typeof i.components?i.components(n):i.components||n:r(i.components),a.createElement(t.Provider,{value:e},i.children)}}}]);